/*
 * GENERATED by scripts/registry-theme.mjs.
 * Source of truth: src/styles/palette.css + src/styles/theme.css.
 *
 * Installed by @c2/base as src/styles/c2-theme.css. Import it from the
 * consuming app's Tailwind entry CSS before installing C2 components.
 */

@import "tw-animate-css";

/*
 * palette.css
 * ───────────
 *
 * Single source of truth for color in the C2 Hub.
 *
 * The DTCG token library (tokens/core.json) references these variables
 * as `{palette.surface-1}`-style aliases; scripts/styleguide-manifest.mjs
 * parses this file at build time and resolves them into the generated
 * artifacts (tokens.generated.css/ts, DESIGN_CONTEXT.md, llms.txt).
 * After editing values here, run `pnpm tokens:build` to refresh them —
 * CI's `pnpm design:check` fails if you forget.
 *
 * Four layers, top → bottom:
 *
 *   1. Slate ramp (--slate-1..12)
 *      Perceptually-uniform OKLCH at hue 256 (cool blue-gray). The
 *      project's neutral spine. Step 1 is the deepest background,
 *      step 12 is the highest-emphasis foreground. Adjacent steps
 *      are ~0.06–0.08 L apart so they're perceptibly distinct.
 *
 *   2. Surface ladder (--surface-void + --surface-1..8)
 *      Eight substrate levels (fluid-functionalism's Surfaces
 *      system) plus a "void" level below substrate 1 for true-black
 *      wells (camera bezels, video iframes, map basemap). Each
 *      level pairs with a shadow recipe so depth reads even when L
 *      deltas are subtle.
 *
 *   3. Borders + state overlays + accents
 *      Tinted hairlines (--border-default/strong/subtle), hover /
 *      pressed / selected interaction washes (--state-*), and
 *      gamut-checked tactical accents (--accent-*) all derived
 *      from the same hue/chroma profile.
 *
 *   4. Disposition tokens (--disposition-*)
 *      Operator labels for track classification. Kept separate
 *      from --accent-* so dispositions and severities can vary
 *      independently.
 *
 * :root holds the dark palette (production default — every route
 * except a styleguide opt-in renders dark). .light flips the slate
 * ramp for the styleguide's "light preview" tool.
 *
 * Painting hook
 * ─────────────
 *
 * <Elevated> (src/primitives/Substrate.tsx) writes data-substrate={N}
 * on its rendered element. The [data-substrate="N"] rules at the
 * bottom of this file project the matching surface + shadow onto two
 * scoped vars (--surface, --shadow) so the primitive only needs
 *
 *   className="bg-[var(--surface)] shadow-[var(--shadow)]"
 *
 * to paint. No inline style mutations on every render.
 *
 * APCA contrast — measured against the hex mirror in accentHex.ts
 * ───────────────────────────────────────────────────────────────
 *
 * Targets:
 *   |Lc| ≥ 60   body text
 *   |Lc| ≥ 75   danger CTA + safety-critical labels
 *   |Lc| ≥ 45   muted / hint / sub-label
 *
 * APCA is dominated by L (chroma effect is small); fix failures
 * by adjusting L on the slate ramp or accent rather than chroma.
 *
 * Foreground on substrate (body / muted use cases)
 *   text-slate-12 on --surface-1    → |Lc| 102   pass++
 *   text-slate-12 on --surface-3    → |Lc|  99   pass++
 *   text-slate-12 on --surface-5    → |Lc|  93   pass++
 *   text-slate-11 on --surface-1    → |Lc|  83   pass+
 *   text-slate-11 on --surface-3    → |Lc|  79   pass+
 *   text-slate-10 on --surface-3    → |Lc|  59   pass (body)
 *   text-slate-9  on --surface-3    → |Lc|  43   pass (muted)
 *   text-slate-8  on --surface-3    → |Lc|  31   DECORATIVE ONLY (icons / hairlines)
 *
 * Accent text on substrate
 *   accent-success on --surface-3   → |Lc|  68   pass (body)
 *   accent-cyan    on --surface-3   → |Lc|  67   pass (body)
 *   accent-info    on --surface-3   → |Lc|  66   pass (body)
 *   accent-warning on --surface-3   → |Lc|  59   borderline body / pass muted
 *   accent-historical on --surface-3→ |Lc|  50   pass muted
 *   accent-tracking on --surface-3  → |Lc|  49   pass muted
 *   accent-danger  on --surface-3   → |Lc|  40   ICON / RING ONLY — do not use as body text
 *
 * Danger CTAs (text on accent fill)
 *   slate-12 on accent-danger-soft  → |Lc|  89   pass (danger CTA target ≥75)
 *   slate-1  on accent-success      → |Lc|  74   pass+
 *   slate-1  on accent-info         → |Lc|  71   pass
 *   slate-1  on accent-warning      → |Lc|  65   pass (CTA-grade with light text-1)
 *
 * Rule of thumb: pair accent fills with slate-1 for "stamped" CTAs
 * and slate-12 for "soft / outline" CTAs. Never paint body copy in
 * accent-danger on dark substrate — use slate-12 + accent-danger
 * as an ICON cue instead.
 */

/* ── 1. Slate ramp (hue 256, dark-tuned) ───────────────────── */
/*
 * Step roles (Radix-style — same job per step in dark and light):
 *
 *   1      App background            (surface-1)
 *   2      Subtle background         (surface-2: cards at rest)
 *   3      UI element background     (surface-3: inputs, chips at rest)
 *   4      Hovered UI element        (surface-4)
 *   5      Active / selected element (surface-5)
 *   6      Subtle borders, separators
 *   7      UI element borders, focus outlines
 *   8      Strong borders, DECORATIVE-ONLY foreground (icons/hairlines)
 *   9      Muted / lowest-contrast readable text
 *   10     Secondary body text
 *   11     Primary body text, labels
 *   12     High-contrast text, headings
 *
 * Steps 1–5 are backgrounds, 6–8 are borders, 9–12 are foregrounds.
 * Contrast receipts for the text steps live in the header above.
 */
:root {
  --slate-1:  oklch(0.165 0.005 256);
  --slate-2:  oklch(0.205 0.006 256);
  --slate-3:  oklch(0.245 0.008 256);
  --slate-4:  oklch(0.290 0.010 256);
  --slate-5:  oklch(0.345 0.012 256);
  --slate-6:  oklch(0.410 0.014 256);
  --slate-7:  oklch(0.490 0.016 256);
  --slate-8:  oklch(0.580 0.018 256);
  --slate-9:  oklch(0.665 0.018 256);
  --slate-10: oklch(0.760 0.018 256);
  --slate-11: oklch(0.870 0.014 256);
  --slate-12: oklch(0.965 0.010 256);
}

/* ── 2. Surface ladder + void + shadows ────────────────────── */
:root {
  /*
   * --surface-void: below the substrate ladder. True-black for
   * camera bezels, video wells, map basemap wells. Documented
   * exception — used intentionally and only where the UI wants
   * "deeper than the deepest surface."
   */
  --surface-void: oklch(0.06 0 0);

  --surface-1: var(--slate-1);
  --surface-2: var(--slate-2);
  --surface-3: var(--slate-3);
  --surface-4: var(--slate-4);
  --surface-5: var(--slate-5);
  --surface-6: var(--slate-6);
  --surface-7: var(--slate-7);
  --surface-8: var(--slate-8);

  --shadow-1: none;
  --shadow-2: 0 1px 2px rgb(0 0 0 / 0.30);
  --shadow-3: 0 2px 4px rgb(0 0 0 / 0.45), 0 1px 2px rgb(0 0 0 / 0.35);
  --shadow-4: 0 4px 8px rgb(0 0 0 / 0.55), 0 2px 4px rgb(0 0 0 / 0.40);
  --shadow-5: 0 8px 16px rgb(0 0 0 / 0.60), 0 4px 8px rgb(0 0 0 / 0.45);
  --shadow-6: 0 12px 24px rgb(0 0 0 / 0.65), 0 6px 12px rgb(0 0 0 / 0.50);
  --shadow-7: 0 16px 32px rgb(0 0 0 / 0.70), 0 8px 16px rgb(0 0 0 / 0.55);
  --shadow-8: 0 24px 48px rgb(0 0 0 / 0.75), 0 12px 24px rgb(0 0 0 / 0.60);
}

/* ── 3a. Borders ───────────────────────────────────────────── */
:root {
  --border-default: oklch(0.490 0.016 256 / 0.55);
  --border-strong:  oklch(0.580 0.018 256 / 0.80);
  --border-subtle:  oklch(0.345 0.012 256 / 0.60);
}

/* ── 3b. Tactical accents (same C% across hues) ────────────── */
/*
 * Each accent's chroma is the same percentage of its hue's
 * max-displayable sRGB chroma at the listed L:
 *
 *   - Vivid: ~100% of hue-max C @ L ≈ 0.70 → "vibrant" rim
 *   - Soft:   ~50% of hue-max C @ L ≈ 0.40 → "dim ember" rim
 *
 * Yields consistent perceived vividness across the palette no
 * matter which hue you pick.
 */
:root {
  --accent-danger:     oklch(0.660 0.220 27);
  --accent-warning:    oklch(0.770 0.170 70);
  --accent-tracking:   oklch(0.715 0.180 50);
  --accent-success:    oklch(0.790 0.180 145);
  --accent-info:       oklch(0.790 0.140 230);
  --accent-historical: oklch(0.720 0.160 280);
  --accent-cyan:       oklch(0.790 0.130 200);
  --accent-magenta:    oklch(0.700 0.200 340);

  --accent-danger-soft:     oklch(0.395 0.110 27);
  --accent-warning-soft:    oklch(0.420 0.090 70);
  --accent-success-soft:    oklch(0.430 0.090 145);
  --accent-info-soft:       oklch(0.430 0.070 230);
  --accent-historical-soft: oklch(0.58 0.19 275);

  /*
   * Interaction tiers for the -soft CTA surfaces (buttons): hover lifts
   * lightness by +0.05, active drops it by −0.05, chroma/hue unchanged so
   * the state change reads as depth, not a hue shift.
   */
  --accent-danger-soft-hover:   oklch(0.445 0.110 27);
  --accent-danger-soft-active:  oklch(0.345 0.110 27);
  --accent-warning-soft-hover:  oklch(0.470 0.090 70);
  --accent-warning-soft-active: oklch(0.370 0.090 70);

  /*
   * Translucent "tint" overlays for highlight rows / pills.
   * Built with color-mix so they always read against the
   * substrate they're painted on top of.
   */
  --accent-success-tint: color-mix(in oklch, var(--accent-success) 11%, transparent);
  --accent-danger-tint:  color-mix(in oklch, var(--accent-danger)  11%, transparent);
  --accent-warning-tint: color-mix(in oklch, var(--accent-warning) 11%, transparent);
  --accent-info-tint:    color-mix(in oklch, var(--accent-info)    11%, transparent);

  /*
   * Accent text tier (Radix step-11 analogue) — lightened low-chroma
   * twins for SMALL TEXT painted over the matching -tint fill or bare
   * substrate, where the vivid accent falls short of body-text contrast
   * (accent-danger on surface-3 is |Lc| 40 — icon/ring only). These sit
   * at L ≈ 0.80–0.87 so 10–11px badge labels stay legible.
   */
  --accent-danger-text:  oklch(0.800 0.105 22);
  --accent-warning-text: oklch(0.875 0.115 85);
  --accent-success-text: oklch(0.870 0.115 155);
  --accent-info-text:    oklch(0.870 0.090 230);
}

/* ── 3c. State overlays (interaction washes) ───────────────── */
/*
 * Derived from --slate-12 via color-mix so they scale with the
 * foreground tone of whichever theme is active. Replaces the
 * scattered rgba(255,255,255,0.04..0.18) magic numbers.
 */
:root {
  --state-hover:        color-mix(in oklch, var(--slate-12) 4%,  transparent);
  --state-hover-strong: color-mix(in oklch, var(--slate-12) 6%,  transparent);
  --state-hover-overlay: color-mix(in oklch, var(--slate-12) 10%, transparent);
  --state-pressed:      color-mix(in oklch, var(--slate-12) 8%,  transparent);
  --state-selected:     color-mix(in oklch, var(--slate-12) 12%, transparent);
  --state-focus-ring:   var(--accent-info);
}

/* ── 4. Dispositions (operator labels — independent of accents) ─ */
:root {
  --disposition-suspect:        oklch(0.745 0.180 60);
  --disposition-assumed-friend: oklch(0.790 0.180 145);
  --disposition-neutral:        oklch(0.700 0.200 340);
}

/* ── data-substrate painting hook ──────────────────────────── */
/*
 * <Elevated data-substrate={N}> → CSS picks --surface + --shadow
 * for that level on the same element. Children inherit nothing —
 * the primitive opens a new SubstrateContext to mark "this is
 * the new floor for any popover that mounts inside me."
 */
[data-substrate="1"] { --surface: var(--surface-1); --shadow: var(--shadow-1); }
[data-substrate="2"] { --surface: var(--surface-2); --shadow: var(--shadow-2); }
[data-substrate="3"] { --surface: var(--surface-3); --shadow: var(--shadow-3); }
[data-substrate="4"] { --surface: var(--surface-4); --shadow: var(--shadow-4); }
[data-substrate="5"] { --surface: var(--surface-5); --shadow: var(--shadow-5); }
[data-substrate="6"] { --surface: var(--surface-6); --shadow: var(--shadow-6); }
[data-substrate="7"] { --surface: var(--surface-7); --shadow: var(--shadow-7); }
[data-substrate="8"] { --surface: var(--surface-8); --shadow: var(--shadow-8); }

/* ── .light: opt-in light-mode preview (styleguide only) ───── */
/*
 * Production routes (/, /demo, /fov-test) never set this class.
 * The styleguide may toggle it on its root to preview foundations
 * under light. Mirror of the slate ramp with L inverted, plus
 * surfaces / borders / states / accents tuned for a white background.
 * Disposition tokens are theme-independent (operator coding stays
 * legible under both themes).
 */
.light {
  --slate-1:  oklch(0.993 0.002 256);
  --slate-2:  oklch(0.982 0.002 256);
  --slate-3:  oklch(0.959 0.004 256);
  --slate-4:  oklch(0.936 0.006 256);
  --slate-5:  oklch(0.914 0.008 256);
  --slate-6:  oklch(0.889 0.010 256);
  --slate-7:  oklch(0.859 0.012 256);
  --slate-8:  oklch(0.811 0.016 256);
  --slate-9:  oklch(0.645 0.018 256);
  --slate-10: oklch(0.501 0.018 256);
  --slate-11: oklch(0.378 0.016 256);
  --slate-12: oklch(0.205 0.006 256);

  --surface-void: oklch(1 0 0);
  --surface-1: var(--slate-1);
  --surface-2: var(--slate-2);
  --surface-3: var(--slate-3);
  --surface-4: var(--slate-4);
  --surface-5: var(--slate-5);
  --surface-6: var(--slate-6);
  --surface-7: var(--slate-7);
  --surface-8: var(--slate-8);

  /*
   * Light-mode shadows are softer (light bg can't carry the same
   * dark drop without looking smudgy). Surfaces 3+ flatten to the
   * same bg as 2 and rely on shadow for elevation, matching
   * fluid-functionalism's light-mode recipe.
   */
  --shadow-1: none;
  --shadow-2: 0 1px 2px rgb(0 0 0 / 0.06);
  --shadow-3: 0 2px 6px rgb(0 0 0 / 0.10), 0 1px 2px rgb(0 0 0 / 0.06);
  --shadow-4: 0 4px 10px rgb(0 0 0 / 0.12), 0 2px 4px rgb(0 0 0 / 0.08);
  --shadow-5: 0 8px 20px rgb(0 0 0 / 0.14), 0 4px 8px rgb(0 0 0 / 0.10);
  --shadow-6: 0 12px 28px rgb(0 0 0 / 0.16), 0 6px 12px rgb(0 0 0 / 0.10);
  --shadow-7: 0 16px 36px rgb(0 0 0 / 0.18), 0 8px 16px rgb(0 0 0 / 0.12);
  --shadow-8: 0 24px 52px rgb(0 0 0 / 0.20), 0 12px 24px rgb(0 0 0 / 0.12);

  --border-default: oklch(0.510 0.016 256 / 0.20);
  --border-strong:  oklch(0.410 0.014 256 / 0.30);
  --border-subtle:  oklch(0.660 0.018 256 / 0.20);

  --state-hover:        color-mix(in oklch, var(--slate-12) 4%,  transparent);
  --state-hover-strong: color-mix(in oklch, var(--slate-12) 6%,  transparent);
  --state-hover-overlay: color-mix(in oklch, var(--slate-12) 10%, transparent);
  --state-pressed:      color-mix(in oklch, var(--slate-12) 8%,  transparent);
  --state-selected:     color-mix(in oklch, var(--slate-12) 12%, transparent);
}

@custom-variant dark (&:is(.dark *));

/*
 * Direction variants
 * ──────────────────
 * Selectors are scoped to the *closest* `[dir]` ancestor (including
 * the element itself). That way:
 *
 *   - `rtl:rotate-180` on a chevron flips it when the page is RTL,
 *     stays put when the page is LTR.
 *   - A subtree wrapped in `<DirIsland direction="ltr">` (which sets
 *     `dir="ltr"` on its root element) breaks the cascade — every
 *     `rtl:*` rule inside that island stops matching, and `ltr:*`
 *     rules start matching, so instrument HUDs / playback timelines
 *     stay LTR even when the app is RTL.
 *
 * Use `rtl:` / `ltr:` only when a *physical* outcome is required
 * (icon rotation, mirroring a transform, hiding a glyph in one
 * direction). For ordinary spacing/positioning prefer Tailwind's
 * logical utilities — `ms-*`, `me-*`, `ps-*`, `pe-*`, `start-*`,
 * `end-*`, `border-s*`, `border-e*`, `rounded-s*`, `rounded-e*`,
 * `text-start`, `text-end` — which do the right thing automatically.
 */
@custom-variant rtl (&:where([dir="rtl"], [dir="rtl"] *));
@custom-variant ltr (&:where([dir="ltr"], [dir="ltr"] *));

/*
 * shadcn semantic layer — aliased onto the tactical palette
 * ─────────────────────────────────────────────────────────
 * Every semantic token below references palette.css (the single source
 * of truth for color). :root is the production dark theme because the
 * palette is dark-by-default; the styleguide's `.light` class flips the
 * slate ramp underneath and every alias here follows automatically —
 * no second value dump needed. (Mapping promoted from
 * theme-sandbox/tokens.ts `deriveTokens()` step 6.)
 */
:root {
  --font-size: 16px;
  --background: var(--surface-1);
  --foreground: var(--slate-12);
  --card: var(--surface-2);
  --card-foreground: var(--slate-12);
  --popover: var(--surface-3);
  --popover-foreground: var(--slate-12);
  --primary: var(--slate-12);
  --primary-foreground: var(--slate-1);
  --secondary: var(--surface-4);
  --secondary-foreground: var(--slate-12);
  --muted: var(--surface-3);
  --muted-foreground: var(--slate-10);
  --accent: var(--surface-4);
  --accent-foreground: var(--slate-12);
  --destructive: var(--accent-danger);
  --destructive-foreground: var(--slate-1);
  --border: var(--border-default);
  --input: var(--surface-3);
  --input-background: var(--surface-3);
  --switch-background: var(--surface-4);
  --font-weight-medium: 500;
  --font-weight-normal: 400;
  --ring: var(--slate-7);
  --chart-1: var(--accent-info);
  --chart-2: var(--accent-success);
  --chart-3: var(--accent-warning);
  --chart-4: var(--accent-historical);
  --chart-5: var(--accent-danger);
  --radius: 0.625rem;
  --sidebar: var(--surface-2);
  --sidebar-foreground: var(--slate-12);
  --sidebar-primary: var(--slate-12);
  --sidebar-primary-foreground: var(--slate-1);
  --sidebar-accent: var(--surface-3);
  --sidebar-accent-foreground: var(--slate-12);
  --sidebar-border: var(--border-default);
  --sidebar-ring: var(--slate-7);
  /* Dot-matrix loader fill (colorPreset="solid-theme"). Tracks foreground. */
  --color-dot-on: var(--slate-12);

  /*
   * Motion tokens — the CSS mirror of `src/lib/springs.ts` (`springMs`).
   * Three speeds, with one-tier-faster exits. The CSS/Radix-overlay layer
   * (tw-animate-css enter/exit) animates on these so it matches the
   * framer-motion springs used elsewhere. `--ease-bounce` is a fast-in /
   * smooth-settle decelerate for entrances (no overshoot/bounce);
   * `--ease-exit` is a quick accelerating curve for exits (so closes never
   * drag).
   */
  --motion-fast: 80ms;
  --motion-moderate: 160ms;
  --motion-slow: 240ms;
  --motion-fast-exit: 60ms;
  --motion-moderate-exit: 120ms;
  --motion-slow-exit: 160ms;
  --ease-bounce: cubic-bezier(0.22, 1, 0.36, 1);
  --ease-exit: cubic-bezier(0.4, 0, 1, 1);
}

/*
 * Overlay motion helpers — map a Radix primitive's enter/exit (driven by
 * tw-animate-css `animate-in` / `animate-out` on `data-state`) onto the three
 * spring tiers from `src/lib/springs.ts`. Entrances use the bounce ease at the
 * tier duration; exits run one tier faster on a plain accelerating curve so
 * closes never drag ("slow in, faster out"). Attribute-scoped so they override
 * tw-animate-css's default `animation-duration`/timing without touching its
 * keyframes. Add one class (`overlay-motion-fast|moderate|slow`) to any Radix
 * Content/Overlay that already carries the `data-[state=*]:animate-*` classes.
 */
/* Entrance: any non-closed state (open / delayed-open / instant-open). */
.overlay-motion-fast[data-state]:not([data-state='closed']),
.overlay-motion-moderate[data-state]:not([data-state='closed']),
.overlay-motion-slow[data-state]:not([data-state='closed']) {
  animation-timing-function: var(--ease-bounce);
}
.overlay-motion-fast[data-state='closed'],
.overlay-motion-moderate[data-state='closed'],
.overlay-motion-slow[data-state='closed'] {
  animation-timing-function: var(--ease-exit);
}
.overlay-motion-fast[data-state]:not([data-state='closed']) {
  animation-duration: var(--motion-fast);
}
.overlay-motion-fast[data-state='closed'] {
  animation-duration: var(--motion-fast-exit);
}
.overlay-motion-moderate[data-state]:not([data-state='closed']) {
  animation-duration: var(--motion-moderate);
}
.overlay-motion-moderate[data-state='closed'] {
  animation-duration: var(--motion-moderate-exit);
}
.overlay-motion-slow[data-state]:not([data-state='closed']) {
  animation-duration: var(--motion-slow);
}
.overlay-motion-slow[data-state='closed'] {
  animation-duration: var(--motion-slow-exit);
}

/*
 * There is intentionally no `.dark { … }` variable block: :root above IS
 * the dark theme (mode convention: dark by default, `.light` opt-in on a
 * subtree — see palette.css). The `.dark` class on <html> remains only so
 * `dark:` Tailwind variants in the shadcn primitives keep matching.
 */

@theme inline {
  --font-sans: "Heebo", sans-serif;
  --font-mono: "IBM Plex Mono", monospace;
  /* Handoff stories: handwritten annotations + code blocks (see /handoff). */
  --font-handwriting: "Caveat", cursive;
  --font-code: "JetBrains Mono", "IBM Plex Mono", monospace;

  --color-background: var(--background);
  --color-foreground: var(--foreground);
  --color-card: var(--card);
  --color-card-foreground: var(--card-foreground);
  --color-popover: var(--popover);
  --color-popover-foreground: var(--popover-foreground);
  --color-primary: var(--primary);
  --color-primary-foreground: var(--primary-foreground);
  --color-secondary: var(--secondary);
  --color-secondary-foreground: var(--secondary-foreground);
  --color-muted: var(--muted);
  --color-muted-foreground: var(--muted-foreground);
  --color-accent: var(--accent);
  --color-accent-foreground: var(--accent-foreground);
  --color-destructive: var(--destructive);
  --color-destructive-foreground: var(--destructive-foreground);
  --color-border: var(--border);
  --color-input: var(--input);
  --color-input-background: var(--input-background);
  --color-switch-background: var(--switch-background);
  --color-ring: var(--ring);
  --color-chart-1: var(--chart-1);
  --color-chart-2: var(--chart-2);
  --color-chart-3: var(--chart-3);
  --color-chart-4: var(--chart-4);
  --color-chart-5: var(--chart-5);
  --radius-sm: calc(var(--radius) - 4px);
  --radius-md: calc(var(--radius) - 2px);
  --radius-lg: var(--radius);
  --radius-xl: calc(var(--radius) + 4px);
  --color-sidebar: var(--sidebar);
  --color-sidebar-foreground: var(--sidebar-foreground);
  --color-sidebar-primary: var(--sidebar-primary);
  --color-sidebar-primary-foreground: var(--sidebar-primary-foreground);
  --color-sidebar-accent: var(--sidebar-accent);
  --color-sidebar-accent-foreground: var(--sidebar-accent-foreground);
  --color-sidebar-border: var(--sidebar-border);
  --color-sidebar-ring: var(--sidebar-ring);
}

@layer base {
  * {
    @apply border-border outline-ring/50;
  }

  body {
    @apply bg-background text-foreground font-sans;
  }

  /**
  * Default typography styles for HTML elements (h1-h4, p, label, button, input).
  * These are in @layer base, so Tailwind utility classes (like text-sm, text-lg) automatically override them.
  */

  html {
    font-size: var(--font-size);
  }

  h1 {
    font-size: var(--text-2xl);
    font-weight: var(--font-weight-medium);
    line-height: 1.5;
  }

  h2 {
    font-size: var(--text-xl);
    font-weight: var(--font-weight-medium);
    line-height: 1.5;
  }

  h3 {
    font-size: var(--text-lg);
    font-weight: var(--font-weight-medium);
    line-height: 1.5;
  }

  h4 {
    font-size: var(--text-base);
    font-weight: var(--font-weight-medium);
    line-height: 1.5;
  }

  label {
    font-size: var(--text-base);
    font-weight: var(--font-weight-medium);
    line-height: 1.5;
  }

  button {
    font-size: var(--text-base);
    font-weight: var(--font-weight-medium);
    line-height: 1.5;
  }

  input {
    font-size: var(--text-base);
    font-weight: var(--font-weight-normal);
    line-height: 1.5;
  }
}

.scrollbar-none {
  scrollbar-width: none;
  -ms-overflow-style: none;
}
.scrollbar-none::-webkit-scrollbar {
  display: none;
}

@keyframes missile-pulse {
  0%, 100% { transform: scale(1); opacity: 1; }
  50% { transform: scale(1.06); opacity: 0.88; }
}

.animate-missile-pulse {
  animation: missile-pulse 0.55s ease-in-out infinite;
}

/* ── ECM jam button: blink twice (bg opacity) when the confirm step arms ── */
@keyframes jam-confirm-blink {
  0%, 30%, 60%, 100% { opacity: 1; }
  15%, 45% { opacity: 0.4; }
}
.animate-jam-confirm-blink {
  animation: jam-confirm-blink 0.7s ease-in-out;
}

/*
 * Sonner toasts — unify built-in toasts with the tactical design
 * language. All values route through palette.css tokens; the 2px corner
 * matches the map-draw panel buttons. `[data-styled]` is matched so
 * sonner's runtime-injected defaults lose to these overrides.
 */
[data-sonner-toast] {
  --normal-bg: var(--surface-3) !important;
  --normal-border: transparent !important;
  --normal-text: var(--slate-12) !important;
  --success-bg: var(--surface-3) !important;
  --success-border: transparent !important;
  --success-text: var(--slate-12) !important;
  --info-bg: var(--surface-3) !important;
  --info-border: transparent !important;
  --info-text: var(--slate-12) !important;
  --warning-bg: var(--surface-3) !important;
  --warning-border: transparent !important;
  --warning-text: var(--slate-12) !important;
  --error-bg: var(--surface-3) !important;
  --error-border: transparent !important;
  --error-text: var(--slate-12) !important;
  background: var(--surface-3) !important;
  border: none !important;
  box-shadow: 0 0 0 1px var(--state-hover-overlay), var(--shadow-5) !important;
  border-radius: 2px !important;
}

[data-sonner-toast] [data-title] {
  font-size: var(--text-sm-minus) !important;
  font-weight: var(--font-weight-medium) !important;
  color: var(--slate-12) !important;
}

[data-sonner-toast] [data-close-button] {
  cursor: pointer !important;
}

/* Toast action / cancel buttons — mirror the map-draw panel's Cancel
   button so an "Undo" affordance in a toast reads as a sibling of the
   panel footer instead of sonner's default filled pill. */
[data-sonner-toast][data-styled='true'] [data-button] {
  height: auto !important;
  padding: 6px 12px !important;
  border-radius: 2px !important;
  border: 1px solid var(--border-subtle) !important;
  background: transparent !important;
  color: var(--slate-11) !important;
  font-size: var(--text-xs) !important;
  font-weight: var(--font-weight-medium) !important;
  line-height: 1 !important;
  transition: background-color 150ms ease, color 150ms ease, border-color 150ms ease !important;
}
[data-sonner-toast][data-styled='true'] [data-button]:hover {
  background: var(--state-hover-strong) !important;
  color: var(--slate-12) !important;
}
[data-sonner-toast][data-styled='true'] [data-button]:focus-visible {
  outline: none !important;
  box-shadow: 0 0 0 2px color-mix(in oklch, var(--slate-12) 25%, transparent) !important;
}

[data-sonner-toast][data-type="success"] [data-icon] {
  color: var(--accent-success) !important;
}
[data-sonner-toast][data-type="info"] [data-icon] {
  color: var(--slate-10) !important;
}
[data-sonner-toast][data-type="warning"] [data-icon] {
  color: var(--accent-warning) !important;
}
[data-sonner-toast][data-type="error"] [data-icon] {
  color: var(--accent-danger) !important;
}

/*
 * RTL transform-origin override for Radix popper-based primitives
 * ───────────────────────────────────────────────────────────────
 *
 * Floating-UI auto-detects RTL via `getComputedStyle(reference).direction`,
 * so it positions popovers/dropdowns/menus correctly in either direction
 * (`align="end"` always anchors to the trigger's inline-end edge — right
 * in LTR, left in RTL).
 *
 * Radix's `transformOrigin` middleware, however, hard-codes a *physical*
 * mapping: `start → 0%`, `center → 50%`, `end → 100%`. That puts the
 * zoom-in animation's origin on the wrong side of the popover in RTL —
 * the box appears to grow *away* from the trigger instead of *out of* it.
 *
 * For top/bottom placements (where RTL only affects the X axis) we flip
 * the X portion of `transform-origin` so the animation grows from the
 * corner adjacent to the trigger. Left/right placements align on the Y
 * axis, which RTL doesn't change, so they're left alone. Set
 * `data-no-rtl-flip` on a content element to opt out of the override.
 */
[dir="rtl"] [data-radix-popper-content-wrapper] > [data-side="bottom"][data-align="start"]:not([data-no-rtl-flip]),
[dir="rtl"] [data-radix-popper-content-wrapper] > [data-side="top"][data-align="start"]:not([data-no-rtl-flip]) {
  transform-origin: 100% 0px;
}

[dir="rtl"] [data-radix-popper-content-wrapper] > [data-side="bottom"][data-align="end"]:not([data-no-rtl-flip]),
[dir="rtl"] [data-radix-popper-content-wrapper] > [data-side="top"][data-align="end"]:not([data-no-rtl-flip]) {
  transform-origin: 0% 0px;
}

/*
 * Recording-clean overrides
 * ─────────────────────────
 *
 * The marketing demo route at `/demo` sets
 * `data-recording-clean="true"` on its root container so screen-capture
 * recordings come out free of incidental UI noise that would otherwise
 * draw the eye away from the scenario being demonstrated:
 *
 *   - Native scrollbars on the right card rail (the rail uses
 *     overflow-y-auto so long logs scroll, but the chrome bar is
 *     distracting and Webkit/Edge each render it differently).
 *   - The high-contrast white focus ring around buttons. Operators
 *     drive the demo with the keyboard, so buttons get focused as the
 *     scenario advances — but a 2 px white ring is the loudest thing
 *     on a dark monochrome map. We tone it down to a 1 px ring at
 *     ~20 % opacity so it's still visible for a11y but doesn't
 *     dominate the frame.
 *
 * Scoped to the recording-clean subtree so the dashboard at `/` is
 * unaffected and continues to use the standard product chrome.
 */
[data-recording-clean="true"] ::-webkit-scrollbar {
  width: 0;
  height: 0;
  background: transparent;
}

[data-recording-clean="true"] {
  scrollbar-width: none;
}

[data-recording-clean="true"] :focus-visible {
  outline: none;
  box-shadow: 0 0 0 1px rgba(255, 255, 255, 0.18);
}

/*
 * Shiki code blocks in the manifest-driven docs. The highlighter runs with
 * `defaultColor: 'dark'`, so token colors are already the github-dark palette;
 * we only neutralise shiki's inline `<pre>` background so the level-0 doc
 * surface shows through instead of github-dark's own #24292e.
 */
.shiki,
.shiki span {
  background-color: transparent !important;
}

/*
 * Cesium credit / attribution bar ("Upgrade for commercial use. Data
 * attribution"). Hidden so the map reads clean to the container edge.
 */
.cesium-viewer-bottom {
  display: none !important;
}

import { clsx, type ClassValue } from "clsx";
import { twMerge } from "tailwind-merge";

export function cn(...inputs: ClassValue[]) {
  return twMerge(clsx(inputs));
}
